# ==================================================================
#   MODBUS COMPATIBILITY WRAPPER
#   pymodbus <=3.6 uses slave=, >=3.7 uses device_id=
# ==================================================================
def _unit_kwarg(func):
    try:
        params = inspect.signature(func).parameters
    except (TypeError, ValueError):
        return "slave"
    if "device_id" in params:
        return "device_id"
    return "slave"


class ModbusLink:
    """Thin, thread-safe wrapper around a ModbusSerialClient."""

    def __init__(self):
        self.client = None
        self.address = 2
        self.lock = threading.Lock()
        self._read_kw = "slave"
        self._write_kw = "slave"

    @property
    def connected(self):
        return self.client is not None and getattr(self.client, "connected", False)

    def connect(self, port, baud, address, timeout=1):
        self.disconnect()
        if not _PYMODBUS_OK:
            raise RuntimeError("pymodbus not installed - run: pip install pymodbus")
        self.client = ModbusSerialClient(
            port=port, baudrate=int(baud), bytesize=8,
            parity="N", stopbits=1, timeout=timeout,
        )
        self._read_kw = _unit_kwarg(self.client.read_holding_registers)
        self._write_kw = _unit_kwarg(self.client.write_register)
        self.address = int(address)
        ok = self.client.connect()
        if not ok:
            self.client = None
        return ok

    def disconnect(self):
        if self.client is not None:
            try:
                self.client.close()
            except Exception:
                pass
        self.client = None

    # -- low level -------------------------------------------------
    def read(self, reg, count=1, address=None):
        """Read holding register(s). Returns list of raw ints or None on error."""
        if self.client is None:
            return None
        addr = self.address if address is None else int(address)
        kw = {self._read_kw: addr, "count": count}
        try:
            rr = self.client.read_holding_registers(reg, **kw)
        except TypeError:
            # older signature: count positional
            try:
                rr = self.client.read_holding_registers(reg, count, **{self._read_kw: addr})
            except Exception:
                return None
        except Exception:
            return None
        if rr is None or (hasattr(rr, "isError") and rr.isError()):
            return None
        return list(rr.registers)

    def write(self, reg, value, address=None):
        """Write single holding register. Returns True/False."""
        if self.client is None:
            return False
        addr = self.address if address is None else int(address)
        kw = {self._write_kw: addr}
        try:
            wr = self.client.write_register(reg, int(value), **kw)
        except Exception:
            return False
        if wr is None or (hasattr(wr, "isError") and wr.isError()):
            return False
        return True


def to_signed16(raw):
    return raw - 65536 if raw > 32767 else raw


